97: /**
98:  * Determines if an address is internal based on user provided config.
99:  */
100: class InternalAddressConfig : public Http::InternalAddressConfig {
101: public:
102:   InternalAddressConfig(const envoy::extensions::filters::network::http_connection_manager::v3::
103:                             HttpConnectionManager::InternalAddressConfig& config,
104:                         absl::Status& creation_status);
105: 
106:   bool isInternalAddress(const Network::Address::Instance& address) const override {
107:     if (address.type() == Network::Address::Type::Pipe) {
108:       return unix_sockets_;
109:     }
110: 
111:     // TODO: cleanup isInternalAddress and default to initializing cidr_ranges_
112:     // based on RFC1918 / RFC4193, if config is unset.
113:     if (cidr_ranges_->getIpListSize() != 0 && address.type() == Network::Address::Type::Ip) {
114:       return cidr_ranges_->contains(address);
115:     }
116:     return Network::Utility::isInternalAddress(address);
117:   }
118: 
119: private:
120:   const bool unix_sockets_;
121:   std::unique_ptr<Network::Address::IpList> cidr_ranges_;
122: };
