47:   enum CodecType {
48:     // For every new connection, the connection manager will determine which
49:     // codec to use. This mode supports both ALPN for TLS listeners as well as
50:     // protocol inference for plaintext listeners. If ALPN data is available, it
51:     // is preferred, otherwise protocol inference is used. In almost all cases,
52:     // this is the right option to choose for this setting.
53:     AUTO = 0;
54: 
55:     // The connection manager will assume that the client is speaking HTTP/1.1.
56:     HTTP1 = 1;
57: 
58:     // The connection manager will assume that the client is speaking HTTP/2
59:     // (Envoy does not require HTTP/2 to take place over TLS or to use ALPN.
60:     // Prior knowledge is allowed).
61:     HTTP2 = 2;
62: 
63:     // The connection manager will assume that the client is speaking HTTP/3.
64:     // This needs to be consistent with listener and transport socket config.
65:     HTTP3 = 3;
66:   }
67: 
68:   enum ServerHeaderTransformation {
69:     // Overwrite any Server header with the contents of server_name.
70:     OVERWRITE = 0;
71: 
72:     // If no Server header is present, append Server server_name
73:     // If a Server header is present, pass it through.
74:     APPEND_IF_ABSENT = 1;
75: 
76:     // Pass through the value of the server header, and do not append a header
77:     // if none is present.
78:     PASS_THROUGH = 2;
79:   }
80: 
81:   // How to handle the :ref:`config_http_conn_man_headers_x-forwarded-client-cert` (XFCC) HTTP
82:   // header.
83:   enum ForwardClientCertDetails {
84:     // Do not send the XFCC header to the next hop. This is the default value.
85:     SANITIZE = 0;
86: 
87:     // When the client connection is mTLS (Mutual TLS), forward the XFCC header
88:     // in the request.
89:     FORWARD_ONLY = 1;
90: 
91:     // When the client connection is mTLS, append the client certificate
92:     // information to the request’s XFCC header and forward it.
93:     APPEND_FORWARD = 2;
94: 
95:     // When the client connection is mTLS, reset the XFCC header with the client
96:     // certificate information and send it to the next hop.
97:     SANITIZE_SET = 3;
98: 
99:     // Always forward the XFCC header in the request, regardless of whether the
100:     // client connection is mTLS.
101:     ALWAYS_FORWARD_ONLY = 4;
102:   }
103: 
104:   // Determines the action for request that contain ``%2F``, ``%2f``, ``%5C`` or ``%5c`` sequences in the URI path.
105:   // This operation occurs before URL normalization and the merge slashes transformations if they were enabled.
106:   enum PathWithEscapedSlashesAction {
107:     // Default behavior specific to implementation (i.e. Envoy) of this configuration option.
108:     // Envoy, by default, takes the KEEP_UNCHANGED action.
109:     //
110:     // .. note::
111:     //
112:     //   The implementation may change the default behavior at-will.
113:     IMPLEMENTATION_SPECIFIC_DEFAULT = 0;
114: 
115:     // Keep escaped slashes.
116:     KEEP_UNCHANGED = 1;
117: 
118:     // Reject client request with the 400 status. gRPC requests will be rejected with the INTERNAL (13) error code.
119:     // The ``httpN.downstream_rq_failed_path_normalization`` counter is incremented for each rejected request.
120:     REJECT_REQUEST = 2;
121: 
122:     // Unescape ``%2F`` and ``%5C`` sequences and redirect request to the new path if these sequences were present.
123:     // Redirect occurs after path normalization and merge slashes transformations if they were configured.
124:     //
125:     // .. note::
126:     //
