746: Http::ServerConnectionPtr HttpConnectionManagerConfig::createCodec(
747:     Network::Connection& connection, const Buffer::Instance& data,
748:     Http::ServerConnectionCallbacks& callbacks, Server::OverloadManager& overload_manager) {
749:   switch (codec_type_) {
750:   case CodecType::HTTP1:
751:     return std::make_unique<Http::Http1::ServerConnectionImpl>(
752:         connection, Http::Http1::CodecStats::atomicGet(http1_codec_stats_, context_.scope()),
753:         callbacks, http1_settings_, maxRequestHeadersKb(), maxRequestHeadersCount(),
754:         headersWithUnderscoresAction(), overload_manager);
755:   case CodecType::HTTP2:
756:     return std::make_unique<Http::Http2::ServerConnectionImpl>(
757:         connection, callbacks,
758:         Http::Http2::CodecStats::atomicGet(http2_codec_stats_, context_.scope()),
759:         context_.serverFactoryContext().api().randomGenerator(), http2_options_,
760:         maxRequestHeadersKb(), maxRequestHeadersCount(), headersWithUnderscoresAction(),
761:         overload_manager);
762:   case CodecType::HTTP3:
763:     return Config::Utility::getAndCheckFactoryByName<QuicHttpServerConnectionFactory>(
764:                "quic.http_server_connection.default")
765:         .createQuicHttpServerConnectionImpl(
766:             connection, callbacks,
767:             Http::Http3::CodecStats::atomicGet(http3_codec_stats_, context_.scope()),
768:             http3_options_, maxRequestHeadersKb(), maxRequestHeadersCount(),
769:             headersWithUnderscoresAction());
770:   case CodecType::AUTO:
771:     return Http::ConnectionManagerUtility::autoCreateCodec(
772:         connection, data, callbacks, context_.scope(),
773:         context_.serverFactoryContext().api().randomGenerator(), http1_codec_stats_,
774:         http2_codec_stats_, http1_settings_, http2_options_, maxRequestHeadersKb(),
775:         maxRequestHeadersCount(), headersWithUnderscoresAction(), overload_manager);
776:   }
777:   PANIC_DUE_TO_CORRUPT_ENUM;
778: }
